const reply = $input.first().json;
const body = reply.body || '';
const subject = reply.subject || '';

let classification = 'UNKNOWN';
let action = null;

const interested = ['interested','yes','tell me more','sounds good','let\'s talk','schedule','call','meeting','appointment'];
const pricing = ['pricing','cost','price','quote','estimate','how much','budget','rate'];
const moreInfo = ['more info','portfolio','examples','case study','previous work','details'];
const notInterested = ['not interested','no thanks','unsubscribe','remove','stop','don\'t contact'];

for (const w of interested) { if (body.includes(w) || subject.includes(w)) { classification = 'INTERESTED'; action = 'send_calendly'; break; } }
for (const w of pricing) { if (body.includes(w)) { classification = 'WANTS_PRICING'; action = 'send_pricing'; break; } }
for (const w of moreInfo) { if (body.includes(w)) { classification = 'WANTS_MORE_INFO'; action = 'send_portfolio'; break; } }
for (const w of notInterested) { if (body.includes(w)) { classification = 'NOT_INTERESTED'; action = 'mark_lost'; break; } }

return {...reply, classification, action, classifiedAt: new Date().toISOString()};

const reply = $input.first().json;
if (reply.action === 'send_calendly') {
  return {to: reply.from, subject: 'Schedule a call with us', body: 'Great to hear from you! Book a time here: {{$env.CALENDLY_EVENT_URL}}', action: 'send_calendly'};
} else if (reply.action === 'send_pricing') {
  return {to: reply.from, subject: 'Pricing Information', body: 'Our landing pages start at $2,500. Would you like a custom quote?', action: 'send_pricing'};
} else if (reply.action === 'mark_lost') {
  return {to: reply.from, subject: 'Thank you', body: 'Thank you for your response. We wish you the best.', action: 'mark_lost'};
}
return {action: 'no_action'};
